var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흠...... 이 사람이 그 기술자인가?","JPN":"ふむ……彼が例のエンジニアか？","ENG":"Hmm... Is this the engineer you spoke of?","TWN":"呃……這個人就是那個技術人員？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너무 젊군. 믿음이 가질 않아.","JPN":"若すぎるな。果たして信用していいものか……","ENG":"Too young. Way too young to earn my trust.","TWN":"太年輕了，我信不過。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"처음 보는 사이에 너무하는군.","JPN":"初対面なのに遠慮がなさすぎるぞ。","ENG":"Well, that's a bit rude considering this is our first time meeting.","TWN":"對初次見面的人，這話說得還真是過分呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정할 필요 없어. 구 관리국의 낡은 보안 시스템 정도는 눈 감고도 해제할 수 있으니까.","JPN":"安心したまえ。旧管理局のカビの生えた\\nセキュリティなんぞは目を瞑ってでも解除できる。","ENG":"Don't worry though. I could disarm an outdated security system from the Old Administration with my eyes closed.","TWN":"不用擔心，舊管理局的老舊安全系統，就算我閉著眼睛也能解除。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"낡은 보안 시스템? 제대로 알긴 하는 건가?","JPN":"カビの生えたセキュリティ？　自分の言ってる意味がわかってるのか？","ENG":"Outdated security system? Do you even know what you're talking about?","TWN":"老舊安全系統？你確定你真的瞭解嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 보안 시스템은 시대를 초월한 기술의 집약체다. 평범한 방법으론 접근조차 할 수 없어.","JPN":"管理局のセキュリティシステムは時代を超越した\\n技術の粋を集めて作られている。通常の方法ではアクセスすらままならぬ代物だ。","ENG":"The Administration's security system is the apex of all technologies beyond time. You won't be able to even access its codes through conventional means.","TWN":"管理局的安保系統是跨時代科技的集合體，一般的方法根本沒辦法連接。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래 봐야 몇 십 년 전에나 쓰던 기술 아닌가? 낡은 건 사실이지.","JPN":"所詮何十年も前に使われた技術だろ？\\nカビが生えているのは確かさ。","ENG":"So? It's still decades old, isn't it? It might be all fancy as you say, but it's still outdated.","TWN":"但不就是幾十年前的技術嘛，老舊是事實啊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너, 배짱은 두둑한 것 같다만......","JPN":"貴様、度胸だけは認めるが……","ENG":"While I applaud your confidence...","TWN":"你，口氣倒是挺大……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그만해, 류드밀라.","JPN":"よしなさい、リュドミラ。","ENG":"Enough, Lyudmila.","TWN":"夠了，盧德米拉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실력은 확실한 사람이야. 내가 보증하지.","JPN":"この人、腕の方は確かよ。私が保証するわ。","ENG":"This engineer has the skills we need. I can vouch for that.","TWN":"他確實是個有實力的人，這我可以保證。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......알겠다. 네가 그렇게 말한다면야.","JPN":"……わかった。君に免じて、ひとまず納得しておこう。","ENG":"Very well. If you say so.","TWN":"……好吧，既然妳都這麼說了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 본 기는 양자좌표석에서 분석된 좌표로 이동 중입니다.</color>","JPN":"<color=#ffd34c>現在、本機は量子座標石で分析された座標へ移動中です。</color>","ENG":"<color=#ffd34c>This ship is currently headed for the coordinates analyzed through the Quantum Coords Crystal.</color>","TWN":"<color=#ffd34c>本機正往量子座標石分析出的座標移動。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_03"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다이브 중 이동은 위험하오니, 탑승자 여러분은 안내 방송 전까지 자리에서 대기해 주십시오.</color>","JPN":"<color=#ffd34c>ダイブ中の移動は危険ですので、搭乗者の皆様はアナウンスがあるまでお席でお待ちください。</color>","ENG":"<color=#ffd34c>All passengers should remain seated until notified as it can be dangerous to move around the cabin during the dive.</color>","TWN":"<color=#ffd34c>在躍入中時移動會發生危險，請搭乘人員聽到廣播之前，坐在位子上待機。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꽤 깐깐한 친구더군. 어린 시절 자네와 친했다는 게 믿기지 않아.","JPN":"彼女はなかなか気難しいタイプだな。\\nあれで幼い頃の君と親友だったとは信じがたい。","ENG":"She seems pretty stiff. I can't believe you used to be close when you were younger.","TWN":"真是位強硬的朋友呢，不敢相信她和妳以前很要好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처음부터 저런 성격은 아니었습니다.","JPN":"はじめからあんな性格ではなかったのです。","ENG":"She wasn't always like that.","TWN":"她一開始的個性不是這樣的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저와 비슷한 시기에 관리국에 들어온 동기였는데...... 그때는 피만 보면 졸도하곤 했었죠.","JPN":"彼女は私と近い時期に管理局に入った同期ですが……\\nあの頃は、血を見ただけで卒倒していました。","ENG":"We joined the Administration around the same time... Back then, she'd pass out at the sight of blood.","TWN":"她和我同期進入管理局……那時候，她一見到血就會暈倒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"피만 보면 졸도해? 그런 사람이 어떻게 전대장까지 올라온 거지?","JPN":"血を見ただけで卒倒？\\nそんな人間がどうやって戦隊長に登り詰めたんだ？","ENG":"She passed out at the sight of blood? How did someone like that ever make it to division commander?","TWN":"一見到血就會暈倒？那樣的人怎麼會晉升到戰隊隊長？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 그땐 당신이 관리자였을 텐데 그걸 제게 물으면 어떡합니까?","JPN":"ちょっと、あの時はあなたが管理者だったはずでしょう？\\n私に聞かれても困りますよ。","ENG":"Hey, you were the Administrator back then! Don't ask me about it!","TWN":"不，你那時候應該就是管理者啊，你怎麼會問我呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펜릴 전대 외의 인사처리 같은 사소한 일은 하이브 컨트롤이 알아서 하게 되어 있네.","JPN":"フェンリル戦隊以外の人事処理のような細かい仕事は\\nハイブコントロールが勝手にやるようになってるからな。","ENG":"Trivial things like personnel were left to Hive Control. Aside from Fenrir, of course.","TWN":"除了芬里爾戰隊以外，其他像人事管理之類的瑣事，都是由巢穴控制系統自動處理的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자라고 해서 시시콜콜 모든 걸 꿰고 있다고 생각하면 오산이야.","JPN":"管理者だからといって、何でもかんでも\\n知り尽くしてると思ったら大間違いだぞ。","ENG":"You'd be mistaken to think that I'd know every little detail just because I'm the Administrator.","TWN":"認為管理者對所有事情都瞭若指掌，這種想法是錯誤的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통을 앞에 세워 두고 한 발 물러서 계시는 건 그때나 지금이나 똑같군요.","JPN":"スクラップ箱を前に立たせて一歩引いておられるのは、\\n今も昔も同じなのですね。","ENG":"So you've always relied on tin cans to do your busy work, huh?","TWN":"擺個鐵罐子來敷衍了事，您從那個時候就和現在一樣了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌거나, 원래는 관제사를 지원하던 친구였습니다만......","JPN":"とにかく、彼女は元々管制官を志していたのですが……","ENG":"In any case, she initially applied for an air traffic controller position...","TWN":"不管怎樣，她原本是志願成為管制員的……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현장에서 죽거나 다치는 동료들을 보면서 어떻게 해야 그들을 지킬 수 있는지 제게 물어보더군요.","JPN":"現場で死んだり怪我をする仲間たちを見て、\\nどうすれば彼らを守れるだろうかと私に相談してきました。","ENG":"But when she saw many of our colleagues die or get hurt in the field, she asked me how she could protect them.","TWN":"但在看到戰場上死去或受傷的夥伴後，她就問我要怎麼做才能保護他們。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？　どう答えたのだね？","ENG":"So?","TWN":"然後呢？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적이 보이기 전에 먼저 날려 버리라고 했죠.","JPN":"敵が視界に入る前にぶっ飛ばすようにアドバイスしました。","ENG":"I told her to blow the enemy away before they even came into sight.","TWN":"我告訴她，只要在敵人出現之前，把他們炸掉就行了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러면 피를 볼 일도, 동료들이 다칠 일도 없을 테니까요.","JPN":"そうすれば血を見ることも、仲間が怪我をすることもないでしょうから。","ENG":"That way, she wouldn't have to see blood, or watch her friends get hurt.","TWN":"這樣就不會看到血，也不會有夥伴受傷。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아주 자네다운 충고로군.","JPN":"……実に君らしい忠告だな。","ENG":"That sure sounds like advice you'd give.","TWN":"……這還真像是妳會給的建議呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 뒤로 무슨 심경의 변화가 있었는지 이를 악물고 전투 훈련을 받더군요.","JPN":"その後、何かしらの心境の変化があったらしく、\\n彼女は必死に戦闘訓練に取り組みました。","ENG":"And then something must have changed her mind. She just sucked it up and went through combat training.","TWN":"後來她的心境不知道發生了什麼變化，開始刻苦進行戰鬥訓練。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"원래도 잠재력이 나쁘지 않은 친구였으니, 금방 실력이 늘어났죠.","JPN":"彼女は元々ポテンシャルが高かったので、瞬く間に実力を伸ばしました。","ENG":"She already had pretty decent potential, so she improved really quickly.","TWN":"她本來就很有潛力，短短時間內，實力就突飛猛進。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 전대장 자리까지 올라갔다고? 그 정도면 천재 소리를 들어도 이상하지 않겠는데?","JPN":"それで戦隊長の座にまで登り詰めたのか？\\n天才と言っても過言ではない成長ぶりだな。","ENG":"And that's how she made it to division commander? Sounds like a prodigy to me!","TWN":"然後就晉升為戰隊隊長？這樣說是天才也不奇怪吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 제가 양보하지 않았더라면 얘기는 달라졌겠지만요.","JPN":"まあ、私が譲っていなければ話は違っていたでしょうね。","ENG":"Well, not if I didn't yield the floor to her.","TWN":"這個嘛，如果我沒有退讓的話，事情可能就不一樣了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전대장 제안은 제게 먼저 왔습니다만, 전 펜릴 전대에 남기로 했으니까요.","JPN":"戦隊長の提案は先に私のところに来ましたが、\\n私はフェンリル戦隊に残ることにしたのですから。","ENG":"I got the offer to be the commander first, but I opted to stay at Fenrir.","TWN":"因為先收到戰隊隊長提議的人是我，但我決定留在芬里爾戰隊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"출세한 동기를 질투하는 모습도 귀엽군, 부사장.","JPN":"出世した同期の友人にヤキモチを焼いているのかね？\\n意外と可愛いところもあるのだな、副社長。","ENG":"Aww, are you jealous of your friend's success, Madame Vice President?","TWN":"妳嫉妒同期的模樣還真可愛，副總。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지, 질투는 무슨! 그런 거 아니거든요?!","JPN":"ヤ、ヤキモチだなんて！　そういうんじゃありません！","ENG":"I-I'm not jealous! It's not what you think!","TWN":"誰、誰嫉妒了！才不是那樣好嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쨌거나 그런 친구가 저런 모습으로 돌아왔으니 기분이 꽤 착잡하겠군.","JPN":"とにかく、その友人があんな姿になって戻ってきたんだ。\\n君もさぞや複雑な心境だろう。","ENG":"In any case, a lot of things must be going through your mind to see your friend return in that state.","TWN":"不管怎樣，妳的那位朋友以那種模樣回來，妳心情應該很複雜吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐......","JPN":"いえ……","ENG":"Well...","TWN":"這個嘛……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금 와선 어쩔 수 없는 일이죠.","JPN":"今となっては、仕方のないことですから。","ENG":"There's nothing I can do about it, really.","TWN":"現在怎麼說都無濟於事了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다이브 종료. 일반 항행 모드로 전환합니다.</color>","JPN":"<color=#ffd34c>ダイブ終了。一般航行モードに切り替わります。</color>","ENG":"<color=#ffd34c>Dive completed. Switching to standard navigation mode.</color>","TWN":"<color=#ffd34c>躍入結束，切換為一般航行模式。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자동 전술 지원 시스템 활성화. 주변에서 다수의 침식파 반응이 확인됩니다.</color>","JPN":"<color=#ffd34c>自動戦術支援システムアクティベーション。周辺から多数の侵食波反応が確認されています。</color>","ENG":"<color=#ffd34c>Automated tactical support system activated. Several Corruption ray responses detected in the vicinity.</color>","TWN":"<color=#ffd34c>自動戰術支援系統已啟動，確認到周圍有大量侵蝕波反應。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_12"},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"도착한 것 같군. 준비는 됐나?","JPN":"着いたようだな。準備はできているか？","ENG":"Sounds like we're here. Are you ready?","TWN":"我們好像到了，準備好了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래. 이쪽은 함선에서 전술지원을 하도록 하지.","JPN":"ええ。こちらは艦船で戦術支援を行うわ。","ENG":"Yes. We'll provide tactical support from the ship.","TWN":"好了，我會在艦船內提供戰術支援。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"수고스럽겠지만 지상은 네가 맡아줘야 할 것 같아.","JPN":"面倒をかけて悪いけど、地上はあなたに任せることになりそうよ。","ENG":"I'm afraid you'll have to take to the ground.","TWN":"雖然有點麻煩，但地面的事情就拜託妳了。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 그쪽은 맡겨 두도록.","JPN":"わかった。任せておけ。","ENG":"Understood. Leave it to me.","TWN":"知道了，地面就交給我吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};